- 'Academically fertile skies' metaphorically represents the courses in which students are enrolled;
- 'Stars' metaphorically represent the students;
- 'Constellations of discussions and assignments' refers to the discussions and assignments published in the relevant courses.

sql:
SELECT course_name 
FROM courses 
WHERE instructor_id IN (SELECT student_id FROM students);

SELECT s.student_name, cg.final_grade
FROM students s
JOIN course_grades cg ON s.student_id = cg.student_id;

SELECT DISTINCT instructors.instructor_name, instructors.contact_number
FROM instructors
INNER JOIN discussions ON instructors.instructor_id = discussions.instructor_id;

